3_real_world_example.code:
class Thermostat {
  constructor(temp) {
    this._temperature = temp; // The 'vault' (underscore is just a naming convention)
  }

  // Runs when someone does: thermo.temp
  get temp() {
    return this._temperature;
  }

  // Runs when someone does: thermo.temp = 500
  set temp(newTemp) {
    if (newTemp > 100) {
      console.log('Error: Too hot!');
      return;
    }
    this._temperature = newTemp;
  }
}

const thermo = new Thermostat(72);
thermo.temp = 150; // 'Error: Too hot!'
console.log(thermo.temp); // 72 (Protects the data!)

